INSERT INTO exhibits (id, name, category, hall, image, description, audioUrl, audioTitle, audioDuration, tags) VALUES
(1,'得天独厚攀枝花','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/1.png','攀枝花市位于川西南、滇西北结合部，是全国唯一以花命名的城市。1965年建市，辖三区两县，面积7440平方公里。','https://wenbovr.top/static/audio/1.mp3','得天独厚攀枝花讲解',154,''),
(2,'生物资源','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/2.jpeg','攀枝花市地处"攀西大裂谷"中南段，自然资源十分丰富，被誉为"富甲天下的聚宝盆"。','','生物资源讲解',0,''),
(3,'矿产资源','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/3.jpeg','攀枝花市已探明铁矿71.8亿吨，钛保有储量6.2亿吨占中国的93%居世界第一。','','矿产资源讲解',0,''),
(4,'植物资源','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/4.jpeg','1987年攀枝花市决定凤凰树为市树、攀枝花为市花。2002年决定攀枝花树为市树。','','植物资源讲解',0,''),
(5,'水果资源','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/5.jpeg','攀枝花芒果具有纤维少、味甜芳香的优良品质，被誉为"热带水果之王"。','','水果资源讲解',0,''),
(6,'文明溯源','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/6.jpeg','何家坝遗址是目前攀枝花地区保存较好的新石器时代人类活动遗址。','','文明溯源讲解',0,''),
(7,'青铜文化','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/7.jpeg','攀枝花地区出土的青铜器冶炼技术成熟，工艺先进，纹饰精美。','','青铜文化讲解',0,''),
(8,'蜀滇要冲','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/8.jpeg','攀枝花境内大约两万年前就有人类活动，成为川滇通道的重要交汇点。','','蜀滇要冲讲解',0,''),
(9,'民族走廊','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/9.jpeg','攀枝花市有41个少数民族，人口175296人，占总人口的14.44%。','','民族走廊讲解',0,''),
(10,'新时期的攀枝花','得天独厚攀枝花','五楼展厅','https://wenbovr.top/static/images/10.jpeg','攀枝花市已发展成为中国西部重要的钢铁、钒钛、能源基地和新兴工业城市。','','新时期的攀枝花讲解',0,''),
(11,'全国三线建设馆','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/11.jpg','三线建设是中华民族工业建设史上一段气壮山河的光辉历程。1964-1980年投入2052.68亿元。','','全国三线建设馆讲解',0,''),
(12,'三线建设的背景','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/12.jpeg','20世纪60年代，面对严峻的国际环境和战争威胁，中共中央作出了三线建设重大决策。','','三线建设的背景讲解',0,''),
(13,'鲲鹏击浪从兹始','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/13.jpeg','从1964年开始，党中央决策和发动了以备战为核心的三线建设。','','鲲鹏击浪从兹始讲解',0,''),
(14,'地动三河铁臂摇','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/14.jpeg','三线建设主要有13个省市，国家投入2052.68亿元，建起1100多个大中型企业。','','地动三河铁臂摇讲解',0,''),
(15,'四川三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/15.jpeg','四川省是三线建设的重中之重，重点项目是"两基一线"。','','四川三线建设讲解',0,''),
(16,'贵州三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/16.jpeg','贵州省三线建设以六盘水煤炭基地和国防科技工业建设为重点。','','贵州三线建设讲解',0,''),
(17,'云南三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/17.jpeg','云南省三线建设建成164个企事业单位，完成投资150.95亿元。','','云南三线建设讲解',0,''),
(18,'甘肃青海宁夏三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/18.jpeg','甘肃三线建设累计投资155.53亿元，新建、迁建和重点改造了156个企事业单位。','','甘肃青海宁夏三线建设讲解',0,''),
(19,'湖北三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/19.jpeg','1964年湖北成为大小三线建设的重点地区之一，国家重点投资项目之多居三线各省前列。','','湖北三线建设讲解',0,''),
(20,'河南三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/20.jpeg','1964年河南省在28个县市展开三线建设，约占河南国土面积的2/3左右。','','河南三线建设讲解',0,''),
(21,'小三线建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/21.jpeg','1965年上海以皖南屯溪为中心建设上海"小三线"后方基地。','','小三线建设讲解',0,''),
(22,'三线建设时期军工厂','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/22.jpeg','三线建设时期，建设基地、企业和军工厂都是保密单位，对外均以代号出现。','','三线建设时期军工厂讲解',0,''),
(23,'三线建设中推动发展的城市','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/23.jpeg','三线建设中，我国中西部崛起了一大批新兴工业新城，如湖北十堰、六盘水市、攀枝花等。','','三线建设中推动发展的城市讲解',0,''),
(24,'三线建设时期的铁路建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/24.jpeg','在三线建设中，铁路是最重要的项目，在中西部修建了多条重要的铁路。','','三线建设时期的铁路建设讲解',0,''),
(25,'三线建设时期的公路建设','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/25.jpeg','公路建设在我国国民经济社会中是必不可少的，早年在三线建设中发挥了不可替代的作用。','','三线建设时期的公路建设讲解',0,''),
(26,'三线建设中的部分重点项目','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/26.jpeg','刘家峡水电站、重庆816核工程等是三线建设的重点项目工程。','','三线建设中的部分重点项目讲解',0,''),
(27,'牵动千万人，人才大集结','全国三线建设馆','四楼展厅','https://wenbovr.top/static/images/27.jpeg','三线建设的数百万建设大军，很多来自上海、北京、沈阳等繁华都市。','','牵动千万人，人才大集结讲解',0,''),
(28,'攀枝花开发建设馆','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/28.jpg','1965年攀枝花特区成立。作为三线建设的活态文化遗产，攀枝花是中国三线建设的成功典范。','','攀枝花开发建设馆讲解',0,''),
(29,'攀枝花开发先声','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/29.jpeg','在上世纪40年代，老一辈的地质工作者就对攀枝花地区的矿产储量进行了实地踏勘。','','攀枝花开发先声讲解',0,''),
(30,'运筹帷幄建设攀枝花','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/30.jpeg','1964年初，攀枝花钢铁基地建设再次进入共和国决策层的视野。','','运筹帷幄建设攀枝花讲解',0,''),
(31,'大军云集','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/31.jpeg','从1964年底开始，来自全国29个省市自治区35个民族的5万多建设者奔赴攀枝花。','','大军云集讲解',0,''),
(32,'三通一住','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/32.jpeg','1965年春天，建设队伍集中力量开展以解决"三通一住"为中心的歼灭战。','','三通一住讲解',0,''),
(33,'主攻两矿，拿下两厂','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/33.jpeg','1966年2月27日，攀枝花建设总指挥部召开万人誓师大会。','','主攻两矿，拿下两厂讲解',0,''),
(34,'夺铁大会战','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/34.jpeg','1970年1月17日，夺铁大会战在弄弄坪拉开战幕，3万多人参加。','','夺铁大会战讲解',0,''),
(35,'大会展时期的生活','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/35.jpeg','大会战建设者的物质生活极其艰苦，但精神生活却十分丰富多彩。','','大会展时期的生活讲解',0,''),
(36,'三线调整','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/36.jpeg','经过"调整改造"，一大批三线企事业单位焕发出蓬勃生机。','','三线调整讲解',0,''),
(37,'共和国不会忘记','攀枝花开发建设馆','三楼展厅','https://wenbovr.top/static/images/37.jpeg','三线建设的伟大贡献和辉煌业绩日益显现，三线精神被广泛颂扬和怀念。','','共和国不会忘记讲解',0,'');